        formatDateTime(utcNow(), 'yyyy-MM-dd HH:mm:ss'),
        ''', updated_at = GETUTCDATE() WHERE pipeline_name = ''PL_Incremental_MedicalClaims''')

scripts.text:
WITH CTE_DEDUP AS (
    SELECT
        ROW_NUMBER() OVER (
            PARTITION BY claim_id, claim_line_id
            ORDER BY source_record_date DESC, CLAIM_FACT_KEY DESC
        ) AS rn
    FROM dbo.medical_claims_staging
)
DELETE FROM CTE_DEDUP WHERE rn > 1;
